1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const ALIKE_BLOCK_SIZE = 3;
4	const ALIKE_BLOCK_PREMIUM = 60;
5	
6	const BASE_PREMIUM: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	  rune: 25,
12	  moonstone: 25,
13	};
14	
15	type Item = { type: string };
16	type Step = { items: Item[] };
17	type Scenario = { steps: Step[] };
18	
19	const isBlockOfAlikeComponents = (items: Item[]): boolean =>
20	  items.length === ALIKE_BLOCK_SIZE &&
21	  items.every((it) => it.type === items[0].type);
22	
23	const sumBasePremiums = (items: Item[]): number =>
24	  items.reduce((acc, { type }) => acc + BASE_PREMIUM[type], 0);
25	
26	const basePremiumForItems = (items: Item[]): number =>
27	  isBlockOfAlikeComponents(items) ? ALIKE_BLOCK_PREMIUM : sumBasePremiums(items);
28	
29	const quotePremium = (items: Item[]): number => {
30	  const basePremium = basePremiumForItems(items);
31	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
32	  return Math.ceil(basePremium + firstInsuranceSurcharge) + PROCESSING_FEE;
33	};
34	
35	export const runScenario = (scenario: Scenario): unknown => {
36	  const results = scenario.steps.map((step) => ({
37	    premium: quotePremium(step.items),
38	  }));
39	  return { results };
40	};
